// Map body.row.* to the 20-column order of the 'Weekly Overview' tab (A:T).
// Image cells arrive already wrapped as =IMAGE("url", 1) formula strings from
// the caller (SKILL.md Media Delivery Contract step 4) and are passed through
// verbatim so Sheets evaluates them into inline images.
const body = $input.first().json.body || {};
const row = body.row || {};
const sheetId = body.sheetId;
if (!sheetId) throw new Error('missing sheetId');

// Documented column order (Weekly Overview!A:T). Fill unknown columns with ''.
const columns = [
  'Week Of',            // A
  'Theme of the Week',  // B
  'Core Content',       // C
  'Image URL',          // D  (=IMAGE() formula)
  'Facebook',           // E
  'Instagram',          // F
  'LinkedIn',           // G
  'X',                  // H
  'TikTok',             // I
  'Pinterest',          // J
  'Google Business',    // K
  'Blog',               // L
  'Email',              // M
  'Podcast',            // N
  'Video',              // O
  'Carousel',           // P
  'Comments',           // Q
  'Scheduled',          // R
  'Overall',            // S
  'Notes'               // T
];
const values = columns.map((c) => (row[c] !== undefined && row[c] !== null ? row[c] : ''));
return [{ json: { sheetId, values } }];

// Resize the image column (D) to 108px wide and the appended data row to 133px
// tall so the =IMAGE() thumbnail displays at full size (INSTALL.md 4f). Two
// batchUpdate calls against the Sheets API; sizing is best-effort and must not
// fail the append.
return [{ json: { note: 'resize image column to 108px and data row to 133px' } }];
